SELECT poi_id, spot_name, name, type, nearest_node_id
FROM pois
WHERE spot_name = #{spotName}
   OR (
     NOT EXISTS (SELECT 1 FROM pois WHERE spot_name = #{spotName})
     AND (
       spot_name LIKE '%' || #{spotName} || '%'
       OR #{spotName} LIKE '%' || spot_name || '%'
     )
   )

SELECT poi_id, spot_name, name, type, nearest_node_id
FROM pois
WHERE (spot_name = #{spotName}
   OR (
     NOT EXISTS (SELECT 1 FROM pois WHERE spot_name = #{spotName})
     AND (
       spot_name LIKE '%' || #{spotName} || '%'
       OR #{spotName} LIKE '%' || spot_name || '%'
     )
   ))
  AND type = #{type}

SELECT poi_id, spot_name, name, type, nearest_node_id
FROM pois
WHERE poi_id = #{poiId}
